#include <stdio.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int A, B, C;
        scanf("%d %d %d", &A, &B, &C);
        if (A > B && A > C) {
            printf("Yes\n");
        } else {
            printf("No\n");
        }
    }
    return 0;
}

